import{_ as e,c as p,o as t,ae as r}from"./chunks/framework.BvcDoAct.js";const S=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2/PART2/7.md","filePath":"zh-cn/Management2/PART2/7.md"}'),o={name:"zh-cn/Management2/PART2/7.md"};function n(s,a,l,i,h,T){return t(),p("div",null,[...a[0]||(a[0]=[r('<p>► 2023/02</p><h2 id="为be-first设定的「宏大梦想」的里程碑" tabindex="-1">为BE:FIRST设定的「宏大梦想」的里程碑 <a class="header-anchor" href="#为be-first设定的「宏大梦想」的里程碑" aria-label="Permalink to &quot;为BE:FIRST设定的「宏大梦想」的里程碑&quot;">​</a></h2><p>#BE:FIRST #持续创造“梦想”的重要性</p><h3 id="「『目標』是能让-可能之事-的实现概率不断膨胀-而『梦想』则拥有让-不可能变为可能-的潜力」" tabindex="-1">「『目標』是能让“可能之事”的实现概率不断膨胀，而『梦想』则拥有让“不可能变为可能”的潜力」 <a class="header-anchor" href="#「『目標』是能让-可能之事-的实现概率不断膨胀-而『梦想』则拥有让-不可能变为可能-的潜力」" aria-label="Permalink to &quot;「『目標』是能让“可能之事”的实现概率不断膨胀，而『梦想』则拥有让“不可能变为可能”的潜力」&quot;">​</a></h3><p><strong>在2月完成了巡回19个城市、共27场公演的「BE:FIRST 1st One Man Tour “BE:1” 2022-2023」后，BE:FIRST从以hall公演为起点，到最终站上arena舞台，在这次巡演中实现了显著成长，并展现出极具分量的舞台表现力。在演出的最后，他们还坚定宣言“在不久的将来要成为能在ドーム开演唱会的艺人”，让人对未来充满期待。当我对SKY-HI说“完全看不出他们才出道一年多”时，他一边回应“是吧？”一边也流露出作为社长冷静的一面。</strong></p><p>正如你看到的那样，从第一年开始就必须达到那种级别的现场表现，这是众多目标中“必须完成”的事情之一。因为我和他们真正想要抵达的地方还在更远的前方，这不过只是一个里程碑。</p><p>如果有一个梦想想要实现，那么梦想越大，所需要的MP（游戏中的魔法值）也就越高，因此所需的努力和能力也会随之提升。从这个意义上来说，我对BE:FIRST的要求确实很高，提出的请求也很多。实际上，看完代代木的演出，我也觉得非常棒，真的很感动。但与此同时，还有很多必须去完成的事情。所以一方面是“太棒了！”的纯粹喜悦，另一方面其实并没有完全沉浸其中。</p><p>不过，即便如此，能在第一年就呈现出这样的舞台表现的艺人并不多见。从「THE FIRST」之后，他们再次证明了我们所做的事情、我们所看到的方向，并没有错。</p><p>自BMSG成立以来，例如选秀「THE FIRST」的成功、自主举办的「BMSG FES」的实现、以及BE:FIRST出演NHK紅白歌合戦等，已经实现了大大小小众多目标。所有这些，都是为了“走向世界”“创造文化”这一宏大梦想的一步。从外界看来，似乎是在围绕梦想制定精密的目标体系，那么战略究竟是如何构建的呢？</p><h3 id="推崇「梦想」的理由" tabindex="-1">推崇「梦想」的理由 <a class="header-anchor" href="#推崇「梦想」的理由" aria-label="Permalink to &quot;推崇「梦想」的理由&quot;">​</a></h3><p>我觉得就是把最重要的事情明确下来，其余部分则保持一定的“模糊性”。其实真正重要的事情并不多。比如对于2022年的BE:FIRST来说，在众多关键目标中，一个非常明确的目标就是“在年末出演红白歌合战”，所以在年初就必须要做出一首爆款歌曲。幸运的是，《Bye-Good-Bye》突破了一亿总播放量，成为大热作品；如果没有达到这个效果，我们原本打算把（收录于首张专辑《BE:1》的）《Message》作为单曲推出。正因为《Bye-Good-Bye》带来了手感，才可以让《Scream》成为专辑主打。虽然会根据目标进行调整，但并不会因此改变“要创作什么样的音乐”……现在回想起来，确实有很多这样的决策。</p><p>之所以把红白歌合战作为目标，是因为它是我们从一开始就设定的“走向世界”的重要里程碑。现阶段虽然还有很多不能说的内容，但一切都是为了实现这个梦想。出道第一年进行hall巡演、登上红白、启动唱跳项目「D.U.N.K.」，全部都是为此而必要的步骤。</p><p>至少，BE:FIRST站上ドーム舞台这一点，我自己是有经验的，因此可以具体想象。但再往后的“世界”层面，在日本的唱跳领域还没有先例。不过，通过观察BTS在全球走红的过程、K-POP的发展轨迹，以及国内成功与失败的项目——无论是身处其中、置身其外，还是旁观——这些经验让我并非无法想象那个未来。从这个意义上来说，把梦想具体化，以及思考为此需要做什么，并不是一件困难的事情。</p><p><strong>SKY-HI表示“我其实挺推荐大家拥有‘梦想’这种东西的”。那背后的理由是什么？</strong></p><p>归根结底，无论你描绘了多么可以想象的梦想，要实现它都需要真正的能力与努力，必须认真去做。但正是在这种“全力以赴”的过程中，往往会遇见比原本设想更精彩的现实。作为促使自己全力投入的担保和燃料，“梦想”是一个非常好的词。</p><h3 id="「目标」与「梦想」的本质区别" tabindex="-1">「目标」与「梦想」的本质区别 <a class="header-anchor" href="#「目标」与「梦想」的本质区别" aria-label="Permalink to &quot;「目标」与「梦想」的本质区别&quot;">​</a></h3><p>过去，（前棒球选手）松坂大輔曾说过类似“我不谈‘梦想’，只有‘目标’”。这种说法一度流行，让人觉得用“目标”更正确。我自己也曾长时间这样认为。但回过头来看，在加入BMSG之前我对Novel Core说的话，以及在「THE FIRST」开始前对周围人说的话，其实都非常不现实。从现在来看，那些与其说是“目标”，不如说包含了大量运气因素。</p><p>“目标”可以扩大实现“可能之事”的概率，而“梦想”则拥有让“不可能变为可能”的潜力。再者，“梦想”这个词本身就带有一种闪闪发光的感觉，而事实也正是如此——通往梦想的过程本身就是闪耀的。因此，作为一种人生方式，我会推荐去拥有“梦想”。</p><p>随着互联网的发展，人类能做到的事情越来越多，现实也变得更加具体。或许正因为如此，那种“比现实再向前半步”的世界，正在变得更具力量。</p><p><strong>如今正处在追逐梦想的途中，SKY-HI的每一天被“远超想象的闪耀瞬间”所点缀，这一点并不难想象。</strong></p><p>比如现在回头看，在开始「THE FIRST」之前，我曾说过“这是《ROOKIES》式的作品”“绝对不会写剧本，与其写剧本，不如把一群怀揣梦想的年轻人聚在一起直接拍摄，那样一定更戏剧化”，这或许是一脉相承的想法。我一直强烈地认为，比起各种虚构作品，现实更加精彩，也更加残酷。因此，忠实地记录现实本身才是最重要的。实际上，「THE FIRST」中确实发生了精彩的现实——现实甚至超越了梦想。</p><p>从这个角度来看，即使把“梦想”具体化，未来也一定还会发生更多更好的事情。听起来或许像是妄想，但当它真正成为现实时，会接连发生许多难以言喻的事情。而且，被称为“梦想”的那些宏大而闪耀的事物，必然会牵涉到很多人。每一个人都有各自的人生，因此一旦产生关联，就会形成“乘法效应”。</p><p>“目标”需要被具体而清晰地设定，而“梦想”则带有某种抽象性，因此每个人都可以用自己的方式去理解它。我觉得，这种可被多元解读的空间，正是“乘法魔力”隐藏的地方。</p><h3 id="如何寻找真正属于自己的「梦想」" tabindex="-1">如何寻找真正属于自己的「梦想」？ <a class="header-anchor" href="#如何寻找真正属于自己的「梦想」" aria-label="Permalink to &quot;如何寻找真正属于自己的「梦想」？&quot;">​</a></h3><p><strong>在日常忙于设定目标、解决眼前问题的商务人士中，也许有不少人已经与“梦想”这个词渐行渐远。</strong></p><p>拥有梦想确实有很多好处，但真正为自己而去做梦，反而并不容易。比如艺人说“梦想是全国巡演”“梦想是Billboard第一”，那究竟是他真正的梦想，还是被模板化的“梦想”？这是需要辨别的。遗憾的是，世界上大量所谓的“梦想”其实是后者，只是模糊地成为一种“应该追求的东西”。</p><p>从这个角度来说，创业公司的存在意义，是通过新的组织去实现社会中存在的问题，而那本身就是一种“梦想”。</p><p>如果一个人真正面对自己的人生，一定会产生一两个“为什么不是这样？”的疑问。当你不断思考这些“为什么”，就会迎来一个“彻底理解（腹落ち）”的瞬间。或许那是能力与意志相匹配的时刻。当你开始觉得“如果能做到这样，世界会更好”，那一刻，才算真正看见了属于自己的梦想。</p><p><strong>他还提到，这种“彻底理解”的瞬间，或许正是接近梦想时才会获得的感受。</strong></p><p>梦想或许就像一座山的顶峰。只有做好准备并持续攀登的人，才能真正看见那座山顶。即便暂时看不见顶峰，在不断攀登与穿越的过程中，总会在某个时刻遇到“啊，就是这座山”的存在。在那之前，仿佛是在被考验。但即使此前的人生并不特别自律或高效，只要内心存在某种不满，沿着它继续追问下去，就一定能找到属于自己的梦想。</p><p>不满与不安几乎是人生常态。但如果只是带着愤怒去面对，基本无法解决问题，最多只是妥协。我自己也曾经历过不得不妥协的生活方式。但在那之中，如果能不自暴自弃地认真思考，其实会逐渐浮现出很多答案。</p><p>而且，当你不放弃地去面对当下环境时，也能从中学到只有在那里才能学到的东西。所以，“不腐化地面对一切”这种生活方式，我是非常推荐的。归根结底，那种闪闪发光的“梦想”思维真的很好。只要是自己真心看见的梦想，即使在别人看来不可能，也绝对不会错。</p>',32)])])}const c=e(o,[["render",n]]);export{S as __pageData,c as default};
